import{_ as e,H as a,f as l,i as r}from"./chunks/framework.eFU6Tutu.js";const p=JSON.parse('{"title":"Помидоры (черри)","description":"","frontmatter":{},"headers":[],"relativePath":"plants/tomatoes.md","filePath":"plants/tomatoes.md"}'),i={name:"plants/tomatoes.md"};function o(n,t,s,d,h,f){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="помидоры-черри" tabindex="-1">Помидоры (черри) <a class="header-anchor" href="#помидоры-черри" aria-label="Permalink to &quot;Помидоры (черри)&quot;">​</a></h1><p>Выращивание помидоров на подоконнике — увлекательное занятие, которое позволит вам получать сладкие и сочные плоды круглый год. Современные карликовые сорта томатов-черри идеально приспособлены для небольшого объёма грунта и радуют урожаем уже через 3-4 месяца после посева.</p><h2 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to &quot;Описание&quot;">​</a></h2><p>Томат — многолетнее растение, но в комнатном цветоводстве его чаще всего выращивают как однолетнюю культуру. Стебель прямостоячий или свисающий (у ампельных форм), требует опоры по мере роста. Листья рассечённые, с характерным «томатным» запахом. Плоды — округлые или сливовидные ягоды массой от 10 до 30 граммов, с разнообразной окраской (красные, жёлтые, оранжевые).</p><h2 id="популярные-сорта-для-дома" tabindex="-1">Популярные сорта для дома <a class="header-anchor" href="#популярные-сорта-для-дома" aria-label="Permalink to &quot;Популярные сорта для дома&quot;">​</a></h2><p>Для подоконника выбирайте супердетерминантные (карликовые) и ампельные сорта, не требующие большого объёма грунта и сложного формирования.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Сорт</th><th style="text-align:left;">Тип роста</th><th style="text-align:left;">Характеристика</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Балконное чудо</strong></td><td style="text-align:left;">Детерминантный, штамбовый</td><td style="text-align:left;">Ранний, высота 30-40 см, плоды красные, массой 15-20 г</td></tr><tr><td style="text-align:left;"><strong>Пиноккио</strong></td><td style="text-align:left;">Детерминантный</td><td style="text-align:left;">Ранний, высота 20-35 см, очень компактный</td></tr><tr><td style="text-align:left;"><strong>Минибел</strong></td><td style="text-align:left;">Детерминантный, карликовый</td><td style="text-align:left;">Ранний, высота 30-40 см, плоды красные, сладкие</td></tr><tr><td style="text-align:left;"><strong>Красная Шапочка</strong></td><td style="text-align:left;">Детерминантный</td><td style="text-align:left;">Ранний, высота 30-40 см, плоды округлые, массой 30-40 г</td></tr><tr><td style="text-align:left;"><strong>Тайни Тим</strong></td><td style="text-align:left;">Детерминантный, карликовый</td><td style="text-align:left;">Очень маленький (до 30 см), усыпан мелкими красными плодами</td></tr><tr><td style="text-align:left;"><strong>Японский карлик</strong></td><td style="text-align:left;">Детерминантный</td><td style="text-align:left;">Ультраранний, высота до 50 см, не требует пасынкования</td></tr></tbody></table><h2 id="уход" tabindex="-1">Уход <a class="header-anchor" href="#уход" aria-label="Permalink to &quot;Уход&quot;">​</a></h2><p>Подробное руководство по выращиванию, пересадке и формировке томатов на подоконнике читайте в <a href="/care/tomatoes.html">гайде по уходу за томатами</a>.</p><h2 id="как-использовать-в-еде" tabindex="-1">Как использовать в еде <a class="header-anchor" href="#как-использовать-в-еде" aria-label="Permalink to &quot;Как использовать в еде&quot;">​</a></h2><p><a href="/recipes/tomatoes.html">Рецепты с помидорами</a></p><ul><li>Свежие салаты (классический капрезе)</li><li>Бутерброды и брускетты</li><li>Запекание с овощами и мясом</li><li>Соусы и пасты</li><li>Украшение блюд</li></ul><h2 id="полезные-своиства" tabindex="-1">Полезные свойства <a class="header-anchor" href="#полезные-своиства" aria-label="Permalink to &quot;Полезные свойства&quot;">​</a></h2><ul><li>Богаты витаминами С, А, группы В и К</li><li>Содержат ликопин — мощный антиоксидант</li><li>Низкая калорийность (около 18 ккал на 100 г)</li><li>Улучшают пищеварение и работу сердечно-сосудистой системы</li><li>Содержат калий и магний</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://pogoda.mail.ru/news/60712543/" target="_blank" rel="noreferrer">Погода Mail — Помидоры на подоконнике</a></li><li><a href="https://azbyka.ru/garden/kak-vyrastit-otlichnye-pomidory-v-gorshkah/" target="_blank" rel="noreferrer">Азбука садовода — Как вырастить отличные помидоры в горшках</a></li><li><a href="https://www.ogorod.ru/daily/ogorod/tomats/39205/vyraschivaem-gorshechnye-tomaty-kruglyy-god-realnaya-strategiya" target="_blank" rel="noreferrer">Огород.ru — Выращиваем горшечные томаты круглый год</a></li></ul><h2 id="похожие-растения" tabindex="-1">Похожие растения <a class="header-anchor" href="#похожие-растения" aria-label="Permalink to &quot;Похожие растения&quot;">​</a></h2><ul><li><a href="/plants/peppers.html">Перцы</a></li><li><a href="/plants/radish.html">Редис</a></li></ul>',18)])])}const y=e(i,[["render",o]]);export{p as __pageData,y as default};
